SELECT AVG(performance_rate) AS average_performance_rate
FROM hospital_performance
WHERE provider_number = 1 AND measurement_period = '2023-Q2';

SELECT provider_number, performance_rate
FROM hospital_performance
WHERE metric_id = 1 AND measurement_period = '2023-Q2';

SELECT hospital_name, bed_count
FROM hospitals
ORDER BY bed_count DESC;

SELECT MAX(performance_rate) AS max_performance_rate
FROM hospital_performance
WHERE metric_id = 1;
